<?php
require_once __DIR__ . '/includes/db.php';
require_once __DIR__ . '/includes/auth.php';
requireLogin();
$id = (int)($_GET['id'] ?? 0);
$user = currentUser();
$stmt = $pdo->prepare('SELECT p.*, u.name AS owner_name, u.email AS owner_email FROM projects p JOIN users u ON p.user_id = u.id WHERE p.id = ? AND p.user_id = ?');
$stmt->execute([$id, $user['id']]);
$project = $stmt->fetch();
if (!$project) die('Report not found');
$report = json_decode($project['ai_report_json'], true) ?: [];
$best = $report['best_idea'] ?? [];
$costs = $report['costs'] ?? [];
$income = $report['income'] ?? [];
$roi = $report['roi'] ?? [];
?>
