    <div class="section"><h2>Financial Plan</h2><div class="grid"><div class="box"><b>Monthly Revenue:</b><br><?= money($income['monthly_revenue_low'] ?? 0) ?> - <?= money($income['monthly_revenue_high'] ?? 0) ?><br><br><b>Monthly Expenses:</b><br><?= money($roi['estimated_monthly_expenses'] ?? 0) ?><br><br><b>Net Profit:</b><br><?= money($roi['estimated_net_profit'] ?? 0) ?><br><br><b>Payback:</b><br><?= e($roi['payback_period_months'] ?? '-') ?> months</div><div class="box"><b>Income Streams</b><ul><?php foreach (($income['income_streams'] ?? []) as $stream): ?><li><?= e($stream) ?></li><?php endforeach; ?></ul><p><?= e($report['break_even']['summary'] ?? '') ?></p></div></div></div>
